calendar_participants__call_permission_never_ask_again__text = TextObject(bs_BA="Pristup vašem telefonu je blokiran.\nOmogućite pristup preko sistemskih\npostavki kako biste mogli započeti poziv.", cs_CZ="Přístup k telefonu je zablokován. Povolte\nprosím přístup v nastavení systému, abyste\nmohli zahájit volání.", da_DK="Adgangen til din telefon er spærret. Tillad\nadgangen via systemindstillingerne for at\nkunne starte opkaldet.", de_DE="Der Zugriff auf dein Telefon ist gesperrt.\nBitte erlaube den Zugriff über die\nSystemeinstellungen, um den Anruf\nstarten zu können.", el_GR="Η πρόσβαση στο τηλέφωνό σας είναι\nφραγμένη. Επιτρέψτε την πρόσβαση μέσω\nτων ρυθμίσεων συστήματος, για να\nμπορέσετε να ξεκινήσετε την κλήση.", en_GB="Access to your phone is locked.\nPlease allow access in the system settings\nto start the call.", es_ES="El acceso al teléfono está bloqueado.\nPermita el acceso en los ajustes del sistema\npara poder iniciar la llamada.", fi_FI="Pääsy puhelimeesi on estetty. Salli pääsy\njärjestelmäasetuksista aloittaaksesi\npuhelun.", fr_FR="L'accès à votre téléphone est bloqué.\nVeuillez autoriser l'accès via les réglages du\nsystème pour pouvoir passer l'appel.", hr_HR="Pristup vašem telefonu je prekinut. Kako\nbiste pokrenuli razgovor, dopustite pristup\npreko sistemskih postavki.", hu_HU="A telefonodhoz való hozzáférés le van tiltva.\nA hívás indításához engedélyezd a\nhozzáférést a rendszerbeállításokon\nkeresztül.", it_IT="L'accesso al Suo telefono è bloccato.\nConsenta l'accesso tramite le impostazioni\ndi sistema per poter avviare la chiamata.", nl_NL="Toegang tot je telefoon is geblokkeerd.\nGelieve toegang te verlenen via de\nsysteeminstellingen om het gesprek te\nkunnen starten.", no_NO="Tilgang til telefonen din er sperret. Gi\ntilgangstillatelse i systeminnstillingene for\nå starte anropet.", pl_PL="Masz zablokowany dostęp do telefonu. Aby\nnawiązać połączenie, zezwól na dostęp w\nustawieniach systemu.", pt_PT="O acesso ao teu telefone está bloqueado.\nPor favor, autoriza o acesso através dos\najustes do sistema para poderes iniciar a\nchamada.", ro_RO="Accesul la telefonul dumneavoastră este\nblocat. Permiteţi accesul prin intermediul\nsetărilor sistemului, pentru a putea iniţia\napelul.", ru_RU="Доступ к вашему телефону заблокирован.\nРазрешите доступ в системных настройках,\nчтобы начать вызов.", sk_SK="Prístup k vášmu telefónu je zablokovaný. Pre\nzačatie rozhovoru povoľte prístup v\nsystémových nastaveniach.", sl_SI="Dostop do vašega telefona je blokiran. Za\nzačetek klica v sistemskih nastavitvah\ndovolite dostop.", sr_RS="Pristup telefonu je blokiran. Dozvolite\npristup preko sistemskih podešavanja da\nbiste mogli započeti poziv.", sv_SE="Åtkomst till din telefon är spärrad. Tillåt\nåtkomst via systeminställningarna för att\nkunna starta samtalet.", tr_TR="Telefonuna erişim bloke edilmiştir. Aramayı\nbaşlatabilmek için lütfen sistem ayarları\nüzerinden erişime izin ver.", uk_UA="Доступ до вашого телефона заблоковано.\nДозвольте доступ у системних настройках,\nщоб розпочати виклик.")
calendar_participants__no_contacts_permission__button_settings = TextObject(bs_BA="Postavke", cs_CZ="Nastavení", da_DK="Indstillinger", de_DE="Einstellungen", el_GR="Ρυθμίσεις", en_GB="Settings", es_ES="Ajustes", fi_FI="Asetukset", fr_FR="Réglages", hr_HR="Namještanja", hu_HU="Beállítások", it_IT="Impostazioni", nl_NL="Instellingen", no_NO="Innstillinger", pl_PL="Ustawienia", pt_PT="Ajustes", ro_RO="Setări", ru_RU="Настройки", sk_SK="Nastavenia", sl_SI="Nastavitve", sr_RS="Podešavanja", sv_SE="Inställningar", tr_TR="Ayarlar", uk_UA="Настройки")
calendar_participants__no_contacts_permission__content = TextObject(bs_BA="Pristup Vašim kontaktima je blokiran. Omogućite pristup\npreko sistemskih postavki kako biste mogli prikazati\nkompletne informacije sa kontaktima.", cs_CZ="Přístup k Vašim kontaktům je zablokován. Povolte prosím\npřístup v nastavení systému, abyste mohli zobrazit úplné\nkontaktní informace.", da_DK="Adgangen til din telefon er spærret. Tillad adgangen via\nsystemindstillingerne for at få vist de fuldstændige\nkontaktinformationer.", de_DE="Der Zugriff auf deine Kontakte ist gesperrt. Bitte erlaube den\nZugriff über die Systemeinstellungen, um dir die\nvollständigen Kontaktinformationen anzeigen zu lassen.", el_GR="Η πρόσβαση στις επαφές σας είναι φραγμένη. Επιτρέψτε την\nπρόσβαση μέσω των ρυθμίσεων συστήματος, για να μπορέσετε\nνα εμφανίσετε τις πλήρεις πληροφορίες επαφών.", en_GB="Access to your contacts is locked. Please allow access in the\nsystem settings to have the complete contact information\ndisplayed.", es_ES="El acceso a los contactos está bloqueado. Permita el acceso en\nlos ajustes del sistema para ver la información de los\ncontactos completa.", fi_FI="Pääsy kontakteihisi on estetty. Salli pääsy\njärjestelmäasetuksista nähdäksesi kaikki kontaktitiedot.", fr_FR="L'accès à vos contacts est bloqué. Veuillez autoriser l'accès via\nles réglages du système pour faire afficher l'ensemble des\ncoordonnées.", hr_HR="Pristup vašim kontaktima je blokiran. Kako biste prikazali\npotpune informacije o kontaktima, dopustite pristup preko\nsistemskih postavki.", hu_HU="A névjegyeidhez való hozzáférés le van tiltva. A teljes\nnévjegyadatok megjelenítéséhez engedélyezd a hozzáférést a\nrendszerbeállításokon keresztül.", it_IT="L'accesso ai contatti è bloccato. Consentire l'accesso tramite\nle impostazioni di sistema per visualizzare le informazioni di\ncontatto complete.", nl_NL="Toegang tot uw contacten is geblokkeerd. Sta toegang toe via\nde systeeminstellingen om uw contactinformatie te bekijken.", no_NO="Tilgang til kontaktene dine er sperret. Gi tilgangstillatelse i\nsysteminnstillingene for å se fullstendig kontaktinformasjon.", pl_PL="Masz zablokowany dostęp do kontaktów. Aby wyświetlić pełne\ndane kontaktowe, zezwól na dostęp w ustawieniach systemu.", pt_PT="O acesso aos teus contactos está bloqueado. Por favor,\nautoriza o acesso nos ajustes do sistema para poderes ver as\ninformações completas dos contactos.", ro_RO="Accesul la contacte este blocat. Permiteţi accesul prin\nintermediul setărilor sistemului, pentru a dispune afişarea\ncompletă a contactelor.", ru_RU="Доступ к вашим контактам заблокирован. Разрешите доступ\nв системных настройках для просмотра всей информации о\nконтактах.", sk_SK="Prístup k vašim kontaktom je zablokovaný. Pre možné\nzobrazenie kontaktných informácií, povoľte prístup\nprostredníctvom systémových nastavení.", sl_SI="Dostop do vaših stikov je blokiran. Za prikaz popolnih\nkontaktnih podatkov v sistemskih nastavitvah dovolite dostop.", sr_RS="Pristup Vašim kontaktima je blokiran. Dozvolite pristup preko\nsistemskih podešavanja da biste mogli prikazati kompletne\ninformacije o kontaktima.", sv_SE="Åtkomst till dina kontakter är spärrad. Tillåt åtkomst via\nsysteminställningarna för att kunna visa den fullständiga\nkontaktinformationen.", tr_TR="Kişilerine erişim bloke edilmiştir. Tam iletişim bilgilerini\ngörüntülemek için lütfen sistem ayarları üzerinden erişime\nizin ver.", uk_UA="Доступ до ваших контактів заблоковано. Дозвольте доступ у\nсистемних настройках для перегляду всієї інформації про\nконтакти.")
calendar_permission_on_phone_revoked_while_using_app_screen__confirm_button__label = TextObject(bs_BA="OK", cs_CZ="OK", da_DK="OK", de_DE="OK", el_GR="OK", en_GB="OK", es_ES="OK", fi_FI="OK", fr_FR="OK", hr_HR="OK", hu_HU="OK", it_IT="OK", nl_NL="OK", no_NO="OK", pl_PL="OK", pt_PT="OK", ro_RO="OK", ru_RU="OK", sk_SK="OK", sl_SI="OK", sr_RS="OK", sv_SE="OK", tr_TR="OK", uk_UA="OK")
calendar_permission_on_phone_revoked_while_using_app_screen__content__text = TextObject(bs_BA="Prvo dodijelite potrebno ovlaštenje za aplikaciju myAudi kako biste mogli koristiti kalendar.", cs_CZ="Nejprve prosím udělte požadované oprávnění v aplikaci myAudi, abyste mohli používat\nkalendář.", da_DK="Tildel først den nødvendige autorisation via myAudi-appen for at kunne anvende kalenderen.", de_DE="Bitte erteile zuerst die erforderliche Berechtigung über die myAudi App, um den Kalender\nnutzen zu können.", el_GR="Χορηγήστε πρώτα την απαιτούμενη εξουσιοδότηση μέσω της εφαρμογής myAudi, για να\nμπορέσετε να χρησιμοποιήσετε το ημερολόγιο.", en_GB="Please assign the necessary authorisation via the myAudi app to use the calendar.", es_ES="Conceda primero el permiso necesario a través de la App myAudi para poder utilizar el\ncalendario.", fi_FI="Myönnä ensin tarvittava oikeus myAudi-sovelluksen kautta kalenterin käyttöä varten.", fr_FR="Veuillez d'abord accorder l'autorisation nécessaire via l'application myAudi pour pouvoir\nutiliser le calendrier.", hr_HR="Kako biste koristili kalendar, prvo dodijelite potrebna odobrenja preko myAudi aplikacije.", hu_HU="A naptár használatához először add meg a szükséges jogosultságot a myAudi alkalmazáson\nkeresztül.", it_IT="Per poter utilizzare il calendario, prima concedere l'autorizzazione necessaria tramite l'app\nmyAudi.", nl_NL="Om de agenda te kunnen gebruiken, eerst de benodigde autorisatie verlenen via de myAudi\napp.", no_NO="Du må gi de nødvendige tilgangsrettighetene i myAudi-appen før du kan bruke kalenderen.", pl_PL="Aby korzystać z Kalendarza, przydziel najpierw wymagane uprawnienie w aplikacji myAudi.", pt_PT="Por favor, aceita primeiro a necessária autorização através da myAudi App para se poder\nutilizar o calendário.", ro_RO="Acordaţi întâi drepturile necesare prin intermediul aplicaţiei myAudi, pentru a putea utiliza\ncalendarul.", ru_RU="Сначала предоставьте необходимое разрешение через приложение myAudi, чтобы иметь\nвозможность пользоваться календарем.", sk_SK="Na používanie kalendára najprv udeľte požadované oprávnenie prostredníctvom aplikácie\nmyAudi.", sl_SI="Za uporabo koledarja v aplikaciji myAudi najprej podelite potrebno pooblastilo.", sr_RS="Molimo Vas da prvo dodelite neophodno ovlašćenje preko aplikacije myAudi da biste mogli\nkoristiti kalendar.", sv_SE="Tilldela först de nödvändiga behörigheterna via myAudi-appen för att kunna använda\nkalendern.", tr_TR="Takvimi kullanabilmek için lütfen önce myAudi uygulaması üzerinden gerekli yetkiyi ver.", uk_UA="Спочатку надайте необхідний дозвіл через програму myAudi, щоб мати можливість\nкористуватися календарем.")
calendar_permission_on_phone_revoked_while_using_app_screen__header__title = TextObject(bs_BA="Kalendar: napomena", cs_CZ="Kalendář: poznámka", da_DK="Kalender: Information", de_DE="Kalender: Hinweis", el_GR="Ημερολόγιο: Υπόδειξη", en_GB="Calendar: Note", es_ES="Calendario: Nota", fi_FI="Kalenteri: ohje", fr_FR="Calendrier: nota", hr_HR="Kalendar: napomena", hu_HU="Naptár: megjegyzés", it_IT="Calendario: avvertenza", nl_NL="Agenda: Opmerking", no_NO="Kalender: Informasjon", pl_PL="Kalendarz: informacja", pt_PT="Calendário: Observação", ro_RO="Calendar: indicaţie", ru_RU="Календарь: примечание", sk_SK="Kalendár: poznámka", sl_SI="Koledar: napotek", sr_RS="Kalendar: napomena", sv_SE="Kalender: Anvisning", tr_TR="Takvim: Not", uk_UA="Календар: примітка")
calendar_reasonbackend_initially_disabled__content__text = TextObject(bs_BA="Došlo je do greške. Trenutno nije raspoloživa važeća licenca.", cs_CZ="Vyskytla se chyba. Aktuálně není nedostupná platná licence.", da_DK="Fejl opstået. P.t. ingen gyldig licens tilgængelig.", de_DE="Es ist ein Fehler aufgetreten. Aktuell ist keine gültige Lizenz verfügbar.", el_GR="Προέκυψε σφάλμα. Προς το παρόν δεν είναι διαθέσιμη εν ισχύ άδεια χρήσης.", en_GB="An error has occurred. There is currently no licence available.", es_ES="Se ha producido un error. No hay ninguna licencia válida disponible actualmente.", fi_FI="Virhe. Voimassa olevaa lisenssiä ei ole tällä hetkellä käytettävissä.", fr_FR="Une erreur s'est produite. Aucune licence valable n'est disponible actuellement.", hr_HR="Pojavila se greška. Trenutačno nema raspoložive važeće licence.", hu_HU="Hiba lépett fel. Jelenleg nem áll rendelkezésre érvényes licenc.", it_IT="Si è verificato un errore. Al momento non è disponibile una licenza valida.", nl_NL="Er is een fout opgetreden. Er is momenteel geen geldige licentie beschikbaar.", no_NO="Det har oppstått en feil. Ingen gyldig lisens tilgjengelig for øyeblikket.", pl_PL="Wystąpił błąd. Aktualnie nie ma dostępnej ważnej licencji.", pt_PT="Ocorreu um erro.Atualmente não estão disponíveis licenças válidas.", ro_RO="A survenit o eroare. Momentan nu este disponibilă nicio licenţă.", ru_RU="Произошла ошибка. На данный момент нет действующей лицензии.", sk_SK="Vyskytla sa chyba. Momentálne nie je k dispozícii žiadna platná licencia.", sl_SI="Prišlo je do napake. Trenutno ni na voljo nobene veljavne licence.", sr_RS="Došlo je do greške. Nije dostupna važeća licenca.", sv_SE="Ett fel har uppstått. För närvarande finns ingen giltig licens tillgänglig.", tr_TR="Bir hata oluştu. Şu anda geçerli bir lisans mevcut değil.", uk_UA="Сталася помилка. Наразі немає чинної ліцензії.")
calendar_reasonbackend_locallydisabled__content__text = TextObject(bs_BA="Došlo je do greške. Usluga je deaktivirana. Aktivirajte uslugu na myAudi portalu ili u myAudi\naplikaciji.", cs_CZ="Vyskytla se závada. Služba je deaktivovaná. Aktivujte prosím službu v portálu myAudi nebo v\naplikaci myAudi.", da_DK="Fejl opstået. Tjeneste deaktiveret. Aktiver tjenesten på myAudi-portalen eller i\nmyAudi-appen.", de_DE="Es ist ein Fehler aufgetreten. Der Dienst ist deaktiviert. Bitte aktiviere den Dienst im myAudi\nPortal oder in der myAudi App.", el_GR="Προέκυψε σφάλμα. Η υπηρεσία είναι απενεργοποιημένη. Ενεργοποιήστε την υπηρεσία στη\nδιαδικτυακή πύλη myAudi ή στην εφαρμογή myAudi.", en_GB="An error has occurred. The service is deactivated. Please activate the service in the myAudi\nportal or the myAudi app.", es_ES="Se ha producido un error. El servicio está desactivado. Actívelo en el portal myAudi o en la\nApp myAudi.", fi_FI="Tapahtui virhe. Palvelu on deaktivoitu. Aktivoi palvelu myAudi-portaalin tai\nmyAudi-sovelluksen kautta.", fr_FR="Une erreur s'est produite. Le service est désactivé. Veuillez activer le service sur le portail\nmyAudi ou dans l'application myAudi.", hr_HR="Nastupila je greška. Usluga je deaktivirana. Aktivirajte uslugu na myAudi portalu ili u myAudi\naplikaciji.", hu_HU="Hiba történt. A szolgáltatás ki van kapcsolva. Kérünk, aktiváld a szolgáltatást a myAudi\nportálon vagy a myAudi alkalmazásban.", it_IT="Si è verificato un errore. Il servizio è disattivato. Attivare il servizio sul portale myAudi o\nnell'app myAudi.", nl_NL="Er is een fout opgetreden. De dienst is gedeactiveerd. Activeer de dienst in het myAudi\nPortaal of in de myAudi App.", no_NO="Det har oppstått en feil. Tjenesten er deaktivert. Aktiver tjenesten i myAudi-portalen eller\nmyAudi-appen.", pl_PL="Pojawił się błąd. Usługa jest wyłączona. Proszę włączyć usługę na portalu myAudi lub w\naplikacji myAudi.", pt_PT="Ocorreu um erro. O serviço está desativado. Por favor, ativa o serviço no portal myAudi ou na\naplicação myAudi.", ro_RO="A survenit o eroare. Serviciul este dezactivat. Activaţi serviciul în portalul myAudi sau în\naplicaţia myAudi.", ru_RU="Произошла ошибка. Сервис отключен. Включите сервис на портале myAudi или в\nприложении myAudi.", sk_SK="Vyskytla sa chyba. Služba je deaktivovaná. Prosím, aktivujte si službu na portáli myAudi alebo\nv aplikácii myAudi.", sl_SI="Prišlo je do napake. Storitev je deaktivirana. Storitev aktivirajte na portalu myAudi ali v\naplikaciji myAudi.", sr_RS="Došlo je do greške. Usluga je deaktivirana. Aktivirajte uslugu na myAudi portalu ili u myAudi\naplikaciji.", sv_SE="Ett fel har uppstått. Tjänsten är avaktiverad. Aktivera tjänsten i myAudi-portalen eller i\nmyAudi-appen.", tr_TR="Bir hata oluştu. Hizmet devre dışı bırakıldı. Lütfen hizmeti myAudi portalında veya myAudi\nuygulamasında etkinleştir.", uk_UA="Сталася помилка. Службу вимкнено. Увімкніть службу на порталі myAudi або у myAudi.")
calendar_reasonbackend_terms_and_conditions_not_accepted__content__text = TextObject(bs_BA="Došlo je do greške. Molimo Vas da prvo prihvatite opće uslove poslovanja na myAudi portalu\nili u myAudi aplikaciji.", cs_CZ="Vyskytla se závada. Nejprve prosím vyjádřete souhlas se všeobecnými obchodními\npodmínkami v portálu myAudi nebo v aplikaci myAudi.", da_DK="Fejl opstået. Accepter først de generelle forretningsbetingelser på myAudi-portalen eller i\nmyAudi-appen.", de_DE="Es ist ein Fehler aufgetreten. Bitte stimme zuerst den allgemeinen Geschäftsbedingungen im\nmyAudi Portal oder in der myAudi App zu.", el_GR="Προέκυψε σφάλμα. Συναινέστε πρώτα στους Γενικούς Όρους και Προϋποθέσεις στη\nδιαδικτυακή πύλη myAudi ή στην εφαρμογή myAudi.", en_GB="An error has occurred. Please first agree to the terms and conditions in the myAudi portal or\nthe myAudi app.", es_ES="Se ha producido un error. Acepte primero los términos y condiciones generales en el portal\nmyAudi o en la App myAudi.", fi_FI="Virhe. Hyväksy ensin yleiset sopimusehdot myAudi-portaalin tai myAudi-sovelluksen kautta.", fr_FR="Une erreur s'est produite. Veuillez d'abord accepter les conditions générales de vente sur le\nportail myAudi ou dans l'application myAudi.", hr_HR="Pojavila se greška. Prvo pristanite na Opće uvjete poslovanja na myAudi portalu ili u myAudi\naplikaciji.", hu_HU="Hiba lépett fel. Kérünk, először fogadd el az Általános Szerződési Feltételeket a myAudi\nportálon vagy a myAudi alkalmazásban.", it_IT="Si è verificato un errore. Prima è necessario accettare le condizioni generali di contratto nel\nportale myAudi o nell'app myAudi.", nl_NL="Er is een fout opgetreden. Ga eerst akkoord met de algemene voorwaarden in het myAudi\nPortaal of in de myAudi App.", no_NO="Det har oppstått en feil. Du må først godta de generelle vilkårene i myAudi-portalen eller\nmyAudi-appen.", pl_PL="Pojawił się błąd. Proszę zaakceptować ogólne warunki handlowe na portalu myAudi lub w\naplikacji myAudi.", pt_PT="Ocorreu um erro. Por favor, aceita primeiro as Condições gerais no portal myAudi ou na\naplicação myAudi.", ro_RO="A survenit o eroare. Acceptaţi întâi condiţiile contractuale generale din portalul myAudi sau\ndin aplicaţia myAudi.", ru_RU="Произошла ошибка. Сначала примите условия и положения пользования на портале\nmyAudi или в приложении myAudi.", sk_SK="Vyskytla sa chyba. Prosím, najskôr odsúhlaste všeobecné obchodné podmienky na portáli\nmyAudi alebo v aplikácii myAudi.", sl_SI="Prišlo je do napake. Najprej se strinjajte s splošnimi pogoji poslovanja na portalu myAudi ali v\naplikaciji myAudi.", sr_RS="Došlo je do greške. Prvo prihvatite opšte uslove poslovanja na myAudi portalu ili myAudi\naplikaciji.", sv_SE="Ett fel har uppstått. Acceptera först de allmänna villkoren i myAudi-portalen eller i\nmyAudi-appen.", tr_TR="Bir hata oluştu. Lütfen önce myAudi portalında veya myAudi uygulamasında genel hükümleri\nve koşulları kabul et.", uk_UA="Сталася помилка. Спочатку прийміть умови користування на порталі myAudi або у\nпрограмі myAudi.")
